                py: "const NOISY_TRIANGLE_WGSL: str = r#\"\nstruct VOut {\n    @builtin(position) pos: vec4<f32>,\n    @location(0) uv: vec2<f32>,\n}\n\n@group(0) @binding(0) var<uniform> color: vec4<f32>\n@group(0) @binding(1) var<uniform> resolution: vec2<f32>\n@group(0) @binding(2) var<uniform> time: f32\n\n@vertex\nfn vs_main(@builtin(vertex_index) i: u32) -> VOut {\n    var p  = array<vec2<f32>, 3>(\n        vec2<f32>(-0.7, -0.4),\n        vec2<f32>( 0.7, -0.4),\n        vec2<f32>( 0.0,  0.8),\n    )\n# Aspect-correct (same trick as step 2) so the triangle keeps shape.\nres = max(resolution, vec2<f32>(1.0))\naspect = res.x / res.y\n    var pos = p[i]\n    if (aspect > 1.0) { pos.x = pos.x / aspect; }\n    else              { pos.y = pos.y * aspect; }\n    var out: VOut\n    out.pos = vec4<f32>(pos, 0.0, 1.0)\n# Use the original (pre-correction) positions as the UV input for noise.\n    out.uv = (p[i] + vec2<f32>(1.0)) * 0.5\n    return out\n}\n\n@fragment\nfn fs_main(in: VOut) -> @location(0) vec4<f32> {\n# simplex2 was pulled in by slug; we just call it.\nn = simplex2(in.uv * 6.0 + vec2<f32>(time * 0.4)) * 0.5 + 0.5\nbreath = 0.55 + 0.45 * n\n    return vec4<f32>(color.rgb * breath, color.a)\n}\n\"#",
                swift: "let NOISY_TRIANGLE_WGSL: str = r#\"\nstruct VOut {\n    @builtin(position) pos: vec4<f32>,\n    @location(0) uv: vec2<f32>,\n}\n\n@group(0) @binding(0) var<uniform> color: vec4<f32>\n@group(0) @binding(1) var<uniform> resolution: vec2<f32>\n@group(0) @binding(2) var<uniform> time: f32\n\n@vertex\nfn vs_main(@builtin(vertex_index) i: u32) -> VOut {\n    var p  = array<vec2<f32>, 3>(\n        vec2<f32>(-0.7, -0.4),\n        vec2<f32>( 0.7, -0.4),\n        vec2<f32>( 0.0,  0.8),\n    )\n    // Aspect-correct (same trick as step 2) so the triangle keeps shape.\nlet res = max(resolution, vec2<f32>(1.0))\nlet aspect = res.x / res.y\n    var pos = p[i]\n    if (aspect > 1.0) { pos.x = pos.x / aspect; }\n    else              { pos.y = pos.y * aspect; }\n    var out: VOut\n    out.pos = vec4<f32>(pos, 0.0, 1.0)\n    // Use the original (pre-correction) positions as the UV input for noise.\n    out.uv = (p[i] + vec2<f32>(1.0)) * 0.5\n    return out\n}\n\n@fragment\nfn fs_main(in: VOut) -> @location(0) vec4<f32> {\n    // simplex2 was pulled in by slug; we just call it.\nlet n = simplex2(in.uv * 6.0 + vec2<f32>(time * 0.4)) * 0.5 + 0.5\nlet breath = 0.55 + 0.45 * n\n    return vec4<f32>(color.rgb * breath, color.a)\n}\n\"#",
                kotlin: "val NOISY_TRIANGLE_WGSL: str = r#\"\nstruct VOut {\n    @builtin(position) pos: vec4<f32>,\n    @location(0) uv: vec2<f32>,\n}\n\n@group(0) @binding(0) var<uniform> color: vec4<f32>\n@group(0) @binding(1) var<uniform> resolution: vec2<f32>\n@group(0) @binding(2) var<uniform> time: f32\n\n@vertex\nfn vs_main(@builtin(vertex_index) i: u32) -> VOut {\n    var p  = array<vec2<f32>, 3>( vec2<f32>(-0.7, -0.4), vec2<f32>( 0.7, -0.4), vec2<f32>( 0.0,  0.8), )\n    // Aspect-correct (same trick as step 2) so the triangle keeps shape.\nval res = max(resolution, vec2<f32>(1.0))\nval aspect = res.x / res.y\n    var pos = p[i]\n    if (aspect > 1.0) { pos.x = pos.x / aspect; }\n    else              { pos.y = pos.y * aspect; }\n    var out: VOut\n    out.pos = vec4<f32>(pos, 0.0, 1.0)\n    // Use the original (pre-correction) positions as the UV input for noise.\n    out.uv = (p[i] + vec2<f32>(1.0)) * 0.5\n    return out\n}\n\n@fragment\nfn fs_main(in: VOut) -> @location(0) vec4<f32> {\n    // simplex2 was pulled in by slug; we just call it.\nval n = simplex2(in.uv * 6.0 + vec2<f32>(time * 0.4)) * 0.5 + 0.5\nval breath = 0.55 + 0.45 * n\n    return vec4<f32>(color.rgb * breath, color.a)\n}\n\"#",
