                js: "const PARTICLE_WGSL = `\nstruct VOut {\n    @builtin(position) pos: vec4<f32>,\n    @location(0) color: vec3<f32>,\n};\n\n@group(0) @binding(0) var<uniform> resolution: vec2<f32>;\n@group(0) @binding(1) var<uniform> time: f32;\n\n@vertex\nfn vs_main(\n    @location(0) position: vec3<f32>,    // per-vertex\n    @location(1) center: vec2<f32>,       // per-instance\n    @location(2) phase: f32,               // per-instance\n    @location(3) tint: vec3<f32>,          // per-instance\n    @location(4) color: vec3<f32>,         // per-vertex\n) -> VOut {\n    let scale = 0.045;\n    let wobble = vec2<f32>(\n        sin(time * 1.3 + phase) * 0.05,\n        cos(time * 0.9 + phase * 1.4) * 0.05,\n    );\n    var world = position.xy * scale + center + wobble;\n    // Aspect-correct so each particle's triangle stays equilateral and\n    // the field stays evenly distributed regardless of canvas shape.\n    let res = max(resolution, vec2<f32>(1.0));\n    let aspect = res.x / res.y;\n    if (aspect > 1.0) { world.x = world.x / aspect; }\n    else              { world.y = world.y * aspect; }\n\n    // Same oscillation as before, routed through \\`easing/in_out_sine\\`\n    // (a registry slug we pulled in at Shader.fetch) for a softer pulse.\n    let raw = 0.5 + 0.5 * sin(time * 2.0 + phase);\n    let glow = 0.4 + 0.6 * in_out_sine(raw);\n\n    var out: VOut;\n    out.pos = vec4<f32>(world, 0.0, 1.0);\n    out.color = color * tint * glow;\n    return out;\n}\n\n@fragment\nfn fs_main(in: VOut) -> @location(0) vec4<f32> {\n    return vec4<f32>(in.color, 1.0);\n}\n`;",
                py: "const PARTICLE_WGSL: str = r#\"\nstruct VOut {\n    @builtin(position) pos: vec4<f32>,\n    @location(0) color: vec3<f32>,\n}\n\n@group(0) @binding(0) var<uniform> resolution: vec2<f32>\n@group(0) @binding(1) var<uniform> time: f32\n\n@vertex\nfn vs_main(\n    @location(0) position: vec3<f32>, # per-vertex\n    @location(1) center: vec2<f32>, # per-instance\n    @location(2) phase: f32, # per-instance\n    @location(3) tint: vec3<f32>, # per-instance\n    @location(4) color: vec3<f32>, # per-vertex\n) -> VOut {\nscale = 0.045\nwobble = vec2<f32>(\n        sin(time * 1.3 + phase) * 0.05,\n        cos(time * 0.9 + phase * 1.4) * 0.05,\n    )\n    var world = position.xy * scale + center + wobble\n# Aspect-correct so each particle's triangle stays equilateral and\n# the field stays evenly distributed regardless of canvas shape.\nres = max(resolution, vec2<f32>(1.0))\naspect = res.x / res.y\n    if (aspect > 1.0) { world.x = world.x / aspect; }\n    else              { world.y = world.y * aspect; }\n\n# Same oscillation as before, routed through `easing/in_out_sine`\n# (a registry slug we pulled in at Shader.new) to soften the\n# peaks and troughs into a slower-feeling pulse.\nraw = 0.5 + 0.5 * sin(time * 2.0 + phase)\nglow = 0.4 + 0.6 * in_out_sine(raw)\n\n    var out: VOut\n    out.pos = vec4<f32>(world, 0.0, 1.0)\n    out.color = color * tint * glow\n    return out\n}\n\n@fragment\nfn fs_main(in: VOut) -> @location(0) vec4<f32> {\n    return vec4<f32>(in.color, 1.0)\n}\n\"#",
                swift: "let PARTICLE_WGSL: str = r#\"\nstruct VOut {\n    @builtin(position) pos: vec4<f32>,\n    @location(0) color: vec3<f32>,\n}\n\n@group(0) @binding(0) var<uniform> resolution: vec2<f32>\n@group(0) @binding(1) var<uniform> time: f32\n\n@vertex\nfn vs_main(\n    @location(0) position: vec3<f32>,    // per-vertex\n    @location(1) center: vec2<f32>,       // per-instance\n    @location(2) phase: f32,               // per-instance\n    @location(3) tint: vec3<f32>,          // per-instance\n    @location(4) color: vec3<f32>,         // per-vertex\n) -> VOut {\nlet scale = 0.045\nlet wobble = vec2<f32>(\n        sin(time * 1.3 + phase) * 0.05,\n        cos(time * 0.9 + phase * 1.4) * 0.05,\n    )\n    var world = position.xy * scale + center + wobble\n    // Aspect-correct so each particle's triangle stays equilateral and\n    // the field stays evenly distributed regardless of canvas shape.\nlet res = max(resolution, vec2<f32>(1.0))\nlet aspect = res.x / res.y\n    if (aspect > 1.0) { world.x = world.x / aspect; }\n    else              { world.y = world.y * aspect; }\n\n    // Same oscillation as before, routed through \"\"\"easing/in_out_sine\"\"\"\n    // (a registry slug we pulled in at Shader.new) to soften the\n    // peaks and troughs into a slower-feeling pulse.\nlet raw = 0.5 + 0.5 * sin(time * 2.0 + phase)\nlet glow = 0.4 + 0.6 * in_out_sine(raw)\n\n    var out: VOut\n    out.pos = vec4<f32>(world, 0.0, 1.0)\n    out.color = color * tint * glow\n    return out\n}\n\n@fragment\nfn fs_main(in: VOut) -> @location(0) vec4<f32> {\n    return vec4<f32>(in.color, 1.0)\n}\n\"#",
                kotlin: "val PARTICLE_WGSL: str = r#\"\nstruct VOut {\n    @builtin(position) pos: vec4<f32>,\n    @location(0) color: vec3<f32>,\n}\n\n@group(0) @binding(0) var<uniform> resolution: vec2<f32>\n@group(0) @binding(1) var<uniform> time: f32\n\n@vertex\nfn vs_main( @location(0) position: vec3<f32>, @location(1) center: vec2<f32>, @location(2) phase: f32, @location(3) tint: vec3<f32>, @location(4) color: vec3<f32>, ) -> VOut {\nval scale = 0.045\nval wobble = vec2<f32>( sin(time * 1.3 + phase) * 0.05, cos(time * 0.9 + phase * 1.4) * 0.05, )\n    var world = position.xy * scale + center + wobble\n    // Aspect-correct so each particle's triangle stays equilateral and\n    // the field stays evenly distributed regardless of canvas shape.\nval res = max(resolution, vec2<f32>(1.0))\nval aspect = res.x / res.y\n    if (aspect > 1.0) { world.x = world.x / aspect; }\n    else              { world.y = world.y * aspect; }\n\n    // Same oscillation as before, routed through \"\"\"easing/in_out_sine\"\"\"\n    // (a registry slug we pulled in at Shader.new) to soften the\n    // peaks and troughs into a slower-feeling pulse.\nval raw = 0.5 + 0.5 * sin(time * 2.0 + phase)\nval glow = 0.4 + 0.6 * in_out_sine(raw)\n\n    var out: VOut\n    out.pos = vec4<f32>(world, 0.0, 1.0)\n    out.color = color * tint * glow\n    return out\n}\n\n@fragment\nfn fs_main(in: VOut) -> @location(0) vec4<f32> {\n    return vec4<f32>(in.color, 1.0)\n}\n\"#",
